// Normalize one WP product into a clean shape and parse price from prose content.
const item = $input.item.json;

const stripHtml = (s) => (s || '')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&hellip;/g, '...')
  .replace(/&#8211;/g, '-')
  .replace(/&#8217;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();

const content = stripHtml(item.content && item.content.rendered);
const excerpt = stripHtml(item.excerpt && item.excerpt.rendered);

// Final price patterns observed on getmodedeals:
//   "...sale for $4.98 – 35% off when you 'clip' the coupon ... = $2.99"
//   "...has X for $9.99"
const eqMatch = content.match(/=\s*\$([0-9,]+(?:\.\d{2})?)/);
const forMatch = content.match(/for\s+\$([0-9,]+(?:\.\d{2})?)/i);
const finalPrice = eqMatch ? eqMatch[1] : (forMatch ? forMatch[1] : null);

// First $-price in the string is usually the "was" price when there's also an "= $X" final price.
const firstDollar = content.match(/\$([0-9,]+(?:\.\d{2})?)/);
const wasPrice = (firstDollar && finalPrice && firstDollar[1] !== finalPrice) ? firstDollar[1] : null;

const featured = item._embedded && item._embedded['wp:featuredmedia'] && item._embedded['wp:featuredmedia'][0];
const image = featured && featured.source_url ? featured.source_url : null;

const blurb = excerpt.length > 140 ? excerpt.slice(0, 137) + '...' : excerpt;

return {
  json: {
    id: item.id,
    title: stripHtml(item.title && item.title.rendered),
    url: item.link,
    image,
    price: finalPrice ? `$${finalPrice}` : null,
    wasPrice: wasPrice ? `$${wasPrice}` : null,
    blurb,
    date: item.date
  }
};

// Aggregate all incoming products into one email payload.
const products = $input.all().map(i => i.json);

const escapeHtml = (s) => String(s || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const cell = (p) => {
  if (!p) {
    return '<td width="50%" style="padding:8px;"></td>';
  }
  const title = escapeHtml(p.title);
  const url = escapeHtml(p.url);
  const image = escapeHtml(p.image);
  const priceBlock = p.price
    ? `<tr><td style="padding:0 14px 8px 14px;font-size:18px;color:#d62828;font-weight:bold;">${escapeHtml(p.price)}${p.wasPrice ? ` <span style="font-size:13px;color:#888;text-decoration:line-through;font-weight:normal;">${escapeHtml(p.wasPrice)}</span>` : ''}</td></tr>`
    : '';
  return `
  <td width="50%" valign="top" style="padding:8px;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#fafafa;border:1px solid #e5e5e5;border-radius:4px;">
      <tr>
        <td align="center" style="padding:12px;">
          <a href="${url}" style="text-decoration:none;">
            <img src="${image}" alt="" width="220" style="max-width:100%;height:auto;display:block;border:0;" />
          </a>
        </td>
      </tr>
      <tr>
        <td style="padding:0 14px 8px 14px;font-size:14px;line-height:1.4;color:#1a1a1a;">
          <a href="${url}" style="color:#1a1a1a;text-decoration:none;font-weight:bold;">${title}</a>
        </td>
      </tr>
      ${priceBlock}
      <tr>
        <td align="center" style="padding:6px 14px 14px 14px;">
          <a href="${url}" style="display:inline-block;background-color:#1a1a1a;color:#ffffff;padding:8px 18px;text-decoration:none;border-radius:3px;font-size:13px;font-weight:bold;">Shop Now</a>
        </td>
      </tr>
    </table>
  </td>`;
};

const rows = [];
for (let i = 0; i < products.length; i += 2) {
  rows.push([products[i], products[i + 1]]);
}
const productRows = rows.map(pair => `<tr>${cell(pair[0])}${cell(pair[1])}</tr>`).join('\n');

const datePretty = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });
const subject = `Today's Top Deals — ${datePretty}`;
const intro = `Here are today's hand-picked deals from across the web. We've got ${products.length} fresh finds for you.`;

const template = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>__SUBJECT__</title></head>
<body style="margin:0;padding:0;background-color:#f4f4f4;font-family:Arial,Helvetica,sans-serif;color:#333;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f4f4f4;"><tr><td align="center" style="padding:20px 10px;">
<table role="presentation" width="600" cellpadding="0" cellspacing="0" border="0" style="background-color:#ffffff;border-radius:4px;overflow:hidden;">
<tr><td align="center" style="background-color:#1a1a1a;padding:20px;"><a href="https://getmodedeals.com" style="text-decoration:none;color:#ffffff;font-size:24px;font-weight:bold;letter-spacing:1px;">GETMODEDEALS</a><div style="color:#cccccc;font-size:12px;margin-top:4px;">__DATE__</div></td></tr>
<tr><td style="padding:24px 24px 8px 24px;"><h1 style="margin:0 0 12px 0;font-size:22px;color:#1a1a1a;">Today's Top Deals</h1><p style="margin:0;font-size:15px;line-height:1.5;color:#444;">__INTRO__</p></td></tr>
<tr><td style="padding:16px 12px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">__ROWS__</table></td></tr>
<tr><td align="center" style="padding:16px 24px 24px 24px;"><a href="https://getmodedeals.com" style="display:inline-block;background-color:#d62828;color:#ffffff;padding:12px 28px;text-decoration:none;border-radius:4px;font-weight:bold;font-size:14px;">See All Deals</a></td></tr>
<tr><td style="background-color:#f4f4f4;padding:20px 24px;font-size:12px;color:#888;line-height:1.5;text-align:center;">You're receiving this because you subscribed at GetModeDeals.com.<br><a href="{{unsubscribe_url}}" style="color:#888;">Unsubscribe</a> &nbsp;|&nbsp; <a href="https://getmodedeals.com" style="color:#888;">Visit site</a><br><span style="color:#aaa;">GetModeDeals &middot; Affiliate links may earn us a commission.</span></td></tr>
</table></td></tr></table></body></html>`;

const html = template
  .replace('__SUBJECT__', escapeHtml(subject))
  .replace('__DATE__', escapeHtml(datePretty))
  .replace('__INTRO__', escapeHtml(intro))
  .replace('__ROWS__', productRows);

return [{
  json: {
    subject,
    html,
    productCount: products.length,
    products
  }
}];
